import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function EditAppointment() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [appointment, setAppointment] = useState({
    lead: "",
    vehicle: "",
    appointmentType: "viewing",
    date: "",
    time: "",
    status: "scheduled",
    notes: "",
  });

  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);

  useEffect(() => {
    const load = async () => {
      try {
        const [apptRes, leadRes, vehicleRes] = await Promise.all([
          api.get(`/appointments/${id}`),
          api.get("/leads"),
          api.get("/vehicles"),
        ]);

        const a = apptRes.data;

        setAppointment({
          lead: a.lead?._id || a.lead || "",
          vehicle: a.vehicle?._id || a.vehicle || "",
          appointmentType: a.appointmentType || "viewing",
          date: a.date ? String(a.date).slice(0, 10) : "",
          time: a.time || "",
          status: a.status || "scheduled",
          notes: a.notes || "",
        });

        setLeads(leadRes.data);
        setVehicles(vehicleRes.data);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load appointment");
        navigate("/appointments");
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    setAppointment({ ...appointment, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();
    try {
      await api.put(`/appointments/${id}`, appointment);
      alert("Appointment updated!");
      navigate("/appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Appointment</div>
          <div className="pageSub">Update appointment details and notes</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
        <form onSubmit={submit}>
        <label className="label">Lead</label>
        <select name="lead" value={appointment.lead} onChange={handleChange} required className="select">
          <option value="">Select Lead</option>
          {leads.map((l) => (
            <option key={l._id} value={l._id}>{l.name}</option>
          ))}
        </select>

        <label className="label" style={{ marginTop: 20 }}>Vehicle</label>
        <select name="vehicle" value={appointment.vehicle} onChange={handleChange} required className="select">
          <option value="">Select Vehicle</option>
          {vehicles.map((v) => (
            <option key={v._id} value={v._id}>
              {v.brand} {v.model || v.type || ""} ({v.year})
            </option>
          ))}
        </select>

        <label className="label" style={{ marginTop: 20 }}>Type</label>
        <select
          name="appointmentType"
          value={appointment.appointmentType}
          onChange={handleChange}
          className="select"
        >
          <option value="viewing">Viewing</option>
          <option value="test_drive">Test Drive</option>
          <option value="follow_up">Follow Up</option>
        </select>

        <label className="label" style={{ marginTop: 20 }}>Date</label>
        <input type="date" name="date" value={appointment.date} onChange={handleChange} required className="input" />

        <label className="label" style={{ marginTop: 20 }}>Time</label>
        <input type="time" name="time" value={appointment.time} onChange={handleChange} required className="input" />

        <label className="label" style={{ marginTop: 20 }}>Status</label>
        <select name="status" value={appointment.status} onChange={handleChange} className="select">
          <option value="scheduled">Scheduled</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>

        <label className="label" style={{ marginTop: 20 }}>Notes</label>
        <textarea
          name="notes"
          value={appointment.notes}
          onChange={handleChange}
          rows={3}
          className="textarea"
          placeholder="Interaction notes"
        />

        <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
          <button type="submit" className="btn btnPrimary">
            Save Changes
          </button>
          <button type="button" onClick={() => navigate("/appointments")} className="btn">
            Cancel
          </button>
        </div>
        </form>
      </div>
    </div>
  );
}
